// 注意这里的类名，要和主文件里 YFJ_Module_ + ucfirst('bazi_paipan') 对应
class YFJ_Module_Bazi_jingpan extends YFJ_Base_Module {

    public function __construct() {
        $this->module_id = 'bazi_jingpan';             // 1. 修改模块 ID
        $this->shortcode = 'yfj_bazi_jingpan';         // 2. 修改短代码
        $this->api_endpoint = '/v1/Bazi/jingpan';      // 3. 配置对应的真实 API 接口

        parent::__construct();

        // 【新增】：单独为“八字流盘”注册“流日流时”的专属异步 AJAX 钩子
        add_action('wp_ajax_yfj_get_liurishi', [$this, 'ajax_handle_liurishi']);
        add_action('wp_ajax_nopriv_yfj_get_liurishi', [$this, 'ajax_handle_liurishi']);
    }

    /**
     * 专属数据拦截与加工引擎 (重写基类方法)
     * 在这里可以对 API 返回的原始数据进行格式化、过滤或追加二次计算的自定义数据。
     */
    protected function process_api_data($raw_data) {
        // 1. 确保数据是数组格式，防止报错
        if (is_array($raw_data)) {
            //如果 API 没返回格局，给个默认的兜底值
            if (!isset($raw_data['base_info']['zhengge'])) {
                $raw_data['base_info']['zhengge'] = '未入格';
            }
        }

        //将处理后的数据返回给 views/result.php 进行渲染
        return $raw_data;
    }

