    /**
     * 【新增中枢】：处理前端流日流时的异步请求 (双模智能分发)
     */
    public function ajax_handle_liurishi() {
        // 1. 安全校验 (防御 CSRF 攻击)
        check_ajax_referer('yfj_nonce', 'nonce');

        // 2. 检查当前环境
        $env = get_option('yfj_environment', 'sandbox');

        if ($env === 'sandbox') {
            // ---> 【沙盒模式】：直接去调用专用的 Mock 方法
            $data = $this->get_demo_liurishi_data($_POST);
            wp_send_json_success($data);

        } else {
            // ---> 【Live 模式】：向缘份居官方发起真实请求
            $api_key = get_option('yfj_api_key');
            if (empty($api_key)) { wp_send_json_error('API Key 未配置或已失效'); }

            // 动态获取当前系统设置的语言 (zh-cn 或 zh-tw)
            $lang = get_option('yfj_language', 'zh-cn');

            // 3. 组装传给缘份居的完整参数 (严格按照 API 文档映射)
            $request_data = [
                'api_key'    => $api_key,
                'year'       => intval($_POST['year'] ?? 0),     // 前端传来的阴历流年
                'month'      => intval($_POST['month'] ?? 0),    // 前端传来的阴历流月
                'sort'       => 2,                               // 官方推荐：按节气排序
                'sex'        => intval($_POST['sex'] ?? 0),
                'bazi_year'  => intval($_POST['bazi_year'] ?? 0),
                'bazi_month' => intval($_POST['bazi_month'] ?? 0),
                'bazi_day'   => intval($_POST['bazi_day'] ?? 0),
                'bazi_hours' => intval($_POST['bazi_hours'] ?? 0),
                'bazi_minute'=> intval($_POST['bazi_minute'] ?? 0),
                'bazi_type'  => intval($_POST['bazi_type'] ?? 1),
                'bazi_sect'  => intval($_POST['bazi_sect'] ?? 2),// 早晚子时流派

                // 真太阳时核心参数
                'zhen'       => intval($_POST['zhen'] ?? 2),
                'province'   => sanitize_text_field($_POST['province'] ?? ''),
                'city'       => sanitize_text_field($_POST['city'] ?? ''),
                'longitude'  => floatval($_POST['longitude'] ?? 0),
                'latitude'   => floatval($_POST['latitude'] ?? 0),

                'lang'       => $lang, // 多语言适配
                'iszip'      => 2      // 强制返回纯文本JSON，方便 PHP 直接解析
            ];

            // 4. 发起 HTTP POST 请求
            $response = wp_remote_post('https://api.yuanfenju.com/index.php/v1/Gongju/liurishi', [
                'body'    => $request_data,
                'timeout' => 15
            ]);

            // 5. 错误处理与数据返回
            if (is_wp_error($response)) { wp_send_json_error('接口网络连接超时'); }

            $body = json_decode(wp_remote_retrieve_body($response), true);
            if (isset($body['errcode']) && $body['errcode'] == 0) {
                wp_send_json_success($body['data']);
            } else {
                wp_send_json_error($body['errmsg'] ?? '获取流日流时失败');
            }
        }
    }
